"use strict";(self.webpackChunkdocu=self.webpackChunkdocu||[]).push([[7711],{2563:(e,i,n)=>{n.r(i),n.d(i,{assets:()=>r,contentTitle:()=>d,default:()=>l,frontMatter:()=>o,metadata:()=>t,toc:()=>h});const t=JSON.parse('{"id":"buddhism/buddhism","title":"Types of buddhism","description":"Zen Buddhism, rooted in Mahayana traditions, places great emphasis on meditation and direct insight over textual study. Originating in China as Chan Buddhism, Zen migrated to Japan, where it became known as \u201cZen.\u201d The central practice is zazen (sitting meditation), which aims to quiet the mind and allow insight into the nature of reality and the concept of \u201cno-self.\u201d Zen teachings focus on direct experience and personal realization, often using koans (paradoxical statements or questions) to transcend rational thought. Zen\u2019s approach is minimalist, emphasizing simplicity and the importance of the present moment.","source":"@site/docs/buddhism/buddhism.md","sourceDirName":"buddhism","slug":"/buddhism/","permalink":"/docs/buddhism/","draft":false,"unlisted":false,"editUrl":"https://github.com/bippyboppy/bippyboppy.github.io/tree/main/docs/buddhism/buddhism.md","tags":[],"version":"current","sidebarPosition":1,"frontMatter":{"title":"Types of buddhism","sidebar_position":1},"sidebar":"tutorialSidebar","previous":{"title":"Reading list","permalink":"/docs/buddhism/Reading"},"next":{"title":"Meditation","permalink":"/docs/buddhism/meditation"}}');var a=n(4848),s=n(8453);const o={title:"Types of buddhism",sidebar_position:1},d="Zen buddhism",r={},h=[];function c(e){const i={h1:"h1",header:"header",p:"p",...(0,s.R)(),...e.components};return(0,a.jsxs)(a.Fragment,{children:[(0,a.jsx)(i.header,{children:(0,a.jsx)(i.h1,{id:"zen-buddhism",children:"Zen buddhism"})}),"\n",(0,a.jsx)(i.p,{children:"Zen Buddhism, rooted in Mahayana traditions, places great emphasis on meditation and direct insight over textual study. Originating in China as Chan Buddhism, Zen migrated to Japan, where it became known as \u201cZen.\u201d The central practice is zazen (sitting meditation), which aims to quiet the mind and allow insight into the nature of reality and the concept of \u201cno-self.\u201d Zen teachings focus on direct experience and personal realization, often using koans (paradoxical statements or questions) to transcend rational thought. Zen\u2019s approach is minimalist, emphasizing simplicity and the importance of the present moment."}),"\n",(0,a.jsx)(i.h1,{id:"pure-land-buddhism",children:"Pure land buddhism"}),"\n",(0,a.jsx)(i.p,{children:"Pure Land Buddhism is centered on faith in the compassionate bodhisattva Amitabha (or Amida) Buddha, who vowed to create a \u201cPure Land\u201d for all who sincerely wish to be reborn there. This tradition, especially popular in East Asia (China, Japan, Korea, and Vietnam), views the Pure Land as a place free from suffering, where practitioners can continue their spiritual practice under ideal conditions. The core practice is reciting Amitabha\u2019s name, often as a mantra, to foster mindfulness and devotion. Pure Land Buddhism is accessible to all, requiring no intensive meditation or scholarly understanding, thus appealing widely across social classes."}),"\n",(0,a.jsx)(i.h1,{id:"theravada-buddhism",children:"Theravada buddhism"}),"\n",(0,a.jsx)(i.p,{children:"Theravada Buddhism, often considered the oldest school, is grounded in the teachings of the Pali Canon. It emphasizes individual enlightenment through the practices the historical Buddha recommended, including morality (sila), meditation (samadhi), and wisdom (panna). This path, sometimes called the \u201cPath of the Elders,\u201d is prominent in Southeast Asian countries like Thailand, Sri Lanka, and Myanmar. Theravada places significant focus on the monastic community (sangha) and encourages lay practitioners to support and learn from the monastics, who follow the Eightfold Path to attain Nirvana, the cessation of suffering."}),"\n",(0,a.jsx)(i.h1,{id:"tibetan-buddhism",children:"Tibetan buddhism"}),"\n",(0,a.jsx)(i.p,{children:"Tibetan Buddhism, also known as Vajrayana or Tantric Buddhism, integrates Mahayana teachings with esoteric practices and rituals developed in Tibet. It emphasizes the potential for enlightenment within one\u2019s lifetime, often through the use of mantras, visualizations, and complex rituals. Tibetan Buddhism is known for its rich symbolism, colorful thangka paintings, mandalas, and the central role of lamas (spiritual teachers), with the Dalai Lama being the most recognized figure. The tradition includes unique practices like lojong (mind training) and Dzogchen (Great Perfection), focusing on direct recognition of one\u2019s Buddha-nature. Tibetan Buddhism is prevalent in Tibet, Nepal, Bhutan, and parts of India."})]})}function l(e={}){const{wrapper:i}={...(0,s.R)(),...e.components};return i?(0,a.jsx)(i,{...e,children:(0,a.jsx)(c,{...e})}):c(e)}},8453:(e,i,n)=>{n.d(i,{R:()=>o,x:()=>d});var t=n(6540);const a={},s=t.createContext(a);function o(e){const i=t.useContext(s);return t.useMemo((function(){return"function"==typeof e?e(i):{...i,...e}}),[i,e])}function d(e){let i;return i=e.disableParentContext?"function"==typeof e.components?e.components(a):e.components||a:o(e.components),t.createElement(s.Provider,{value:i},e.children)}}}]);